module accu(
    input clk, input rst_n, input [7:0] data_in, input valid_in,
    output reg valid_out, output reg [9:0] data_out
);
    reg [7:0] data_in_reg [3:0];
    reg [9:0] data_out_reg;
    reg [1:0] counter;
    reg valid_out_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            counter <= 0;
            valid_out_reg <= 0;
            data_out_reg <= 0;
            valid_out <= 0;
            data_out <= 0;
            data_in_reg[0] <= 0;
            data_in_reg[1] <= 0;
            data_in_reg[2] <= 0;
            data_in_reg[3] <= 0;
        end else begin
            if (valid_in) begin
                data_in_reg[counter] <= data_in;
                counter <= counter + 1;
                if (counter == 2'b11) begin
                    data_out_reg <= data_in_reg[0] + data_in_reg[1] + data_in_reg[2] + data_in_reg[3];
                    valid_out_reg <= 1;
                    counter <= 0;
                end else begin
                    valid_out_reg <= 0;
                end
            end else begin
                valid_out_reg <= 0;
            end
            valid_out <= valid_out_reg;
            data_out <= data_out_reg;
        end
    end
endmodule
